# ─────────────────────────────────────────────
#  Core data functions (unchanged logic)
# ─────────────────────────────────────────────
def load_shopee_file(file):
    if file.name.endswith('.xlsx'):
        df = pd.read_excel(file, engine='calamine', header=None)
    else:
        try:
            df = pd.read_csv(file, encoding='utf-8-sig', header=None)
        except Exception:
            df = pd.read_csv(file, encoding='utf-8', header=None)
    header_idx = 0
    for idx, row in df.head(10).iterrows():
        row_vals = row.astype(str).str.strip()
        if '商品ID' in row_vals.values:
            header_idx = idx
            break
    df.columns = df.iloc[header_idx].astype(str).str.strip()
    df = df.iloc[header_idx + 1:].reset_index(drop=True)
    if '商品ID' in df.columns:
        df = df.dropna(subset=['商品ID'])
        df = df[df['商品ID'].astype(str).str.contains(r'\d', regex=True, na=False)]
    return df


def validate_data(df, lang):
    errors = []
    if '商品名稱' in df.columns:
        lengths = df['商品名稱'].astype(str).str.len()
        invalid_count = (~lengths.between(10, 60, inclusive='both') & df['商品名稱'].notna()).sum()
        if invalid_count > 0:
            if lang == "zh":
                errors.append(f"⚠️ {invalid_count} 筆商品的「商品名稱」長度不符合規定（需為 10–60 字元）。")
            else:
                errors.append(f"⚠️ {invalid_count} product(s) have an invalid 'Product Name' length (must be 10–60 chars).")
    desc_col = '商品描述_basic' if '商品描述_basic' in df.columns else ('商品描述' if '商品描述' in df.columns else None)
    if desc_col:
        lengths = df[desc_col].astype(str).str.len()
        invalid_count = (~lengths.between(3, 3000, inclusive='both') & df[desc_col].notna()).sum()
        if invalid_count > 0:
            if lang == "zh":
                errors.append(f"⚠️ {invalid_count} 筆商品的「商品描述」長度不符合規定（需為 3–3000 字元）。")
            else:
                errors.append(f"⚠️ {invalid_count} product(s) have an invalid 'Description' length (must be 3–3000 chars).")
    return errors


