def page_merge(t):
    st.markdown(f'<div class="hero-header"><h1>{t["hero_title"]}</h1><p>{t["hero_sub"]}</p></div>', unsafe_allow_html=True)

    st.markdown(f'<div class="section-header">{t["upload_section"]}</div>', unsafe_allow_html=True)

    col1, col2, col3 = st.columns(3)

    with col1:
        st.markdown(f'<div class="step-card"><div class="step-label">{t["step1_label"]}</div><div class="step-title">{t["step1_title"]}</div>', unsafe_allow_html=True)
        sales_file = st.file_uploader(t["upload_hint"], type=['csv', 'xlsx'], key="sales", label_visibility="collapsed")
        st.markdown('</div>', unsafe_allow_html=True)

    with col2:
        st.markdown(f'<div class="step-card"><div class="step-label">{t["step2_label"]}</div><div class="step-title">{t["step2_title"]}</div>', unsafe_allow_html=True)
        basic_file = st.file_uploader(t["upload_hint"], type=['csv', 'xlsx'], key="basic", label_visibility="collapsed")
        st.markdown('</div>', unsafe_allow_html=True)

    with col3:
        st.markdown(f'<div class="step-card"><div class="step-label">{t["step3_label"]}</div><div class="step-title">{t["step3_title"]}</div>', unsafe_allow_html=True)
        media_file = st.file_uploader(t["upload_hint"], type=['csv', 'xlsx'], key="media", label_visibility="collapsed")
        st.markdown('</div>', unsafe_allow_html=True)

    st.markdown("<br>", unsafe_allow_html=True)
    merge_clicked = st.button(t["merge_btn"], type="primary", use_container_width=True)

    if merge_clicked:
        if not (sales_file and basic_file and media_file):
            st.warning(t["warn_upload"])
            return

        with st.status(t["merge_btn"], expanded=True) as status:
            try:
                st.write(t["status_reading"])
                sales_df = load_shopee_file(sales_file)
                basic_df = load_shopee_file(basic_file)
                media_df = load_shopee_file(media_file)

                st.write(t["status_merging"])
                id_col = '商品ID'
                if not all(id_col in df.columns for df in [sales_df, basic_df, media_df]):
                    st.error(t["error_missing_id"])
                    status.update(label="Error", state="error")
                    st.stop()

                for df in [sales_df, basic_df, media_df]:
                    df[id_col] = df[id_col].astype(str).str.strip()

                merged_df = sales_df.merge(basic_df, on=id_col, how='left', suffixes=('', '_basic'))
                merged_df = merged_df.merge(media_df, on=id_col, how='left', suffixes=('', '_media'))

                target_columns = [
                    "分類", "商品名稱", "商品描述", "最低購買數量", "主商品貨號", "危險物品",
                    "商品規格識別碼", "規格名稱 1", "規格選項 1", "規格圖片", "規格名稱 2",
                    "規格選項 2", "價格", "庫存", "商品選項貨號", "新版尺寸表", "圖片尺寸表",
                    "GTIN", "主商品圖片", "商品圖片 1", "商品圖片 2", "商品圖片 3", "商品圖片 4",
                    "商品圖片 5", "商品圖片 6", "商品圖片 7", "商品圖片 8", "重量", "長度",
                    "寬度", "高度", "黑貓宅急便", "7-ELEVEN", "全家", "萊爾富", "萊爾富-經濟包",
                    "宅配通", "蝦皮店到店", "店到家宅配 - 標準包裹", "嘉里快遞",
                    "蝦皮店到店 - 隔日到貨", "新竹物流", "店到家宅配 - 大型包裹", "較長備貨天數",
                    "失敗原因"
                ]

                col_mapping = {"分類": "商品分類"}

                mapped_df = pd.DataFrame(columns=target_columns)
                for col in target_columns:
                    source_col = col_mapping.get(col, col)
                    if source_col in merged_df.columns:
                        mapped_df[col] = merged_df[source_col]
                    elif f"{source_col}_basic" in merged_df.columns:
                        mapped_df[col] = merged_df[f"{source_col}_basic"]
                    elif f"{source_col}_media" in merged_df.columns:
                        mapped_df[col] = merged_df[f"{source_col}_media"]

                if '商品規格名稱' in merged_df.columns:
                    valid_mask = (
                        merged_df['商品規格名稱'].notna() &
                        (merged_df['商品規格名稱'] != 'nan') &
                        (merged_df['商品規格名稱'].astype(str).str.strip() != '')
                    )
                    mapped_df.loc[valid_mask, '商品規格識別碼'] = merged_df.loc[valid_mask, '商品ID']
                    mapped_df.loc[~valid_mask, '商品規格識別碼'] = ''

                    str_opts = merged_df.loc[valid_mask, '商品規格名稱'].astype(str)
                    if not str_opts.empty:
                        split_opts = str_opts.str.split(',', n=1, expand=True)
                        mapped_df.loc[valid_mask, '規格選項 1'] = split_opts[0]
                        if len(split_opts.columns) > 1:
                            mapped_df.loc[valid_mask, '規格選項 2'] = split_opts[1]

                def get_variation_image(mapped_row, merged_row):
                    tier1_name = str(mapped_row.get('規格選項 1', '')).strip()
                    if not tier1_name or tier1_name == 'nan':
                        return ''
                    for i in range(1, 51):
                        name_col = f'選項 {i} 的名稱'
                        if name_col in merged_row.index:
                            if str(merged_row.get(name_col, '')).strip() == tier1_name:
                                return merged_row.get(f'選項 {i} 的圖片', '')
                    return ''

                images = [get_variation_image(mapped_df.iloc[i], merged_df.iloc[i]) for i in range(len(mapped_df))]
                mapped_df['規格圖片'] = images

                if '分類' in mapped_df.columns:
                    extracted_ids = mapped_df['分類'].astype(str).str.extract(r'^(\d+)')[0]
                    mapped_df['分類'] = extracted_ids.fillna(mapped_df['分類'])

                if '商品描述' in mapped_df.columns:
                    mask = mapped_df['商品描述'].notna()
                    mapped_df.loc[mask, '商品描述'] = (
                        mapped_df.loc[mask, '商品描述']
                        .astype(str)
                        .str.replace(r'https?://[^\s]+', '', regex=True)
                        .str.replace(r'\n\s*\n', '\n', regex=True)
                        .str.strip()
                    )
                    if '商品名稱' in mapped_df.columns:
                        short_mask = mapped_df['商品描述'].isna() | (mapped_df['商品描述'].astype(str).str.len() < 3)
                        mapped_df.loc[short_mask, '商品描述'] = mapped_df.loc[short_mask, '商品名稱']

                final_output_df = mapped_df

                # Metrics
                total_rows = len(final_output_df)
                variant_rows = int((final_output_df['商品規格識別碼'].astype(str).str.strip() != '').sum()) if '商品規格識別碼' in final_output_df.columns else 0
                simple_rows = total_rows - variant_rows

                st.write(t["status_template"])

                # 從程式內嵌的 Base64 字串解碼，完全不需要外部檔案
                import base64 as _b64
                _wb_bytes = _b64.b64decode(_MAINSHEET_B64)
                wb = openpyxl.load_workbook(io.BytesIO(_wb_bytes))
                if '上傳模板' not in wb.sheetnames:
                    st.error("mainsheet.xlsx 中找不到「上傳模板」工作表！")
                    status.update(label="Error", state="error")
                    st.stop()

                ws = wb['上傳模板']
                data_values_df = pd.DataFrame(final_output_df.values)
                for row in dataframe_to_rows(data_values_df, index=False, header=False):
                    ws.append(row)

                output_buf = io.BytesIO()
                wb.save(output_buf)
                excel_data = output_buf.getvalue()

                status.update(label=t["status_done"], state="complete", expanded=False)

            except Exception as e:
                st.error(f"{t['error_critical']}{str(e)}")
                status.update(label="Error", state="error")
                st.stop()

        # ── Results dashboard ──
        st.markdown("<br>", unsafe_allow_html=True)
        m1, m2, m3 = st.columns(3)
        m1.metric(t["metric_total"], total_rows)
        m2.metric(t["metric_variant"], variant_rows)
        m3.metric(t["metric_simple"], simple_rows)

        validation_errors = validate_data(merged_df, st.session_state.get("lang", "zh"))
        if validation_errors:
            st.warning(t["validation_err"])
            for err in validation_errors:
                st.markdown(err)
        else:
            st.success(t["validation_ok"])

        st.markdown(f'<div class="section-header">{t["preview_header"]}</div>', unsafe_allow_html=True)
        st.dataframe(final_output_df.head(20).fillna("").astype(str), use_container_width=True)

        st.markdown("<br>", unsafe_allow_html=True)
        st.download_button(
            label=t["download_btn"],
            data=excel_data,
            file_name="mainsheet_ready.xlsx",
            mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            use_container_width=True
        )

    render_footer(t)


# ─────────────────────────────────────────────
#  Main entrypoint
# ─────────────────────────────────────────────
def main():
    if "lang" not in st.session_state:
        st.session_state["lang"] = "zh"

    lang = st.session_state["lang"]
    t = LANG[lang]

    with st.sidebar:
        st.markdown("""
        <div style="text-align:center; padding: 20px 0 10px 0;">
            <span style="font-size:2.5rem;">🦐</span>
            <div style="font-size:16px;font-weight:700;color:#ee4d2d;margin-top:6px;">蝦皮合併神器</div>
            <div style="font-size:11px;color:#888;margin-top:2px;">Shopee Data Merge Tool</div>
        </div>
        <hr style="border-color:rgba(238,77,45,0.3);margin:10px 0 16px 0;">
        """, unsafe_allow_html=True)

        page = st.radio(
            "Navigation",
            [t["nav_tool"], t["nav_guide"]],
            label_visibility="collapsed"
        )

        st.markdown("<hr style='border-color:rgba(255,255,255,0.08);margin:20px 0 12px 0;'>", unsafe_allow_html=True)

        # Language switcher — clearly labelled
        current_flag = "🇹🇼 繁體中文" if lang == "zh" else "🇺🇸 English"
        switch_label = "🇺🇸 Switch to English" if lang == "zh" else "🇹🇼 切換中文"
        st.markdown(f"<div style='font-size:11px;color:#666;margin-bottom:6px;text-align:center;'>目前語言 / Language</div>", unsafe_allow_html=True)
        st.markdown(f"<div style='text-align:center;font-size:13px;color:#aaa;font-weight:600;margin-bottom:10px;'>{current_flag}</div>", unsafe_allow_html=True)
        if st.button(switch_label, use_container_width=True, key="lang_btn"):
            st.session_state["lang"] = "en" if lang == "zh" else "zh"
            st.rerun()

        st.markdown("<br><br>", unsafe_allow_html=True)
        st.markdown(f"""
        <div style="text-align:center;font-size:11px;color:#444;line-height:1.8;">
            © 2025 杉蔓有限公司<br>
            <a href="https://www.sustainablemans.com/" target="_blank" style="color:#ee4d2d;text-decoration:none;">sustainablemans.com</a>
        </div>
        """, unsafe_allow_html=True)

    if page == t["nav_guide"]:
        page_guide(t)
    else:
        page_merge(t)


if __name__ == "__main__":
    main()
